function Wait-Window([int]$ProcessId,[int]$Seconds=15){$c=New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::ProcessIdProperty,$ProcessId);for($i=0;$i-lt $Seconds*5;$i++){$w=[System.Windows.Automation.AutomationElement]::RootElement.FindFirst([System.Windows.Automation.TreeScope]::Children,$c);if($w){return $w};Start-Sleep -Milliseconds 200};throw '找不到窗口'}
function Find-One($Root,[string]$Name,$Type=$null){$cs=New-Object System.Collections.Generic.List[System.Windows.Automation.Condition];if($Name-ne''){$cs.Add((New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::NameProperty,$Name)))};if($Type){$cs.Add((New-Object System.Windows.Automation.PropertyCondition([System.Windows.Automation.AutomationElement]::ControlTypeProperty,$Type)))};$c=if($cs.Count-eq 1){$cs[0]}else{New-Object System.Windows.Automation.AndCondition($cs.ToArray())};$Root.FindFirst([System.Windows.Automation.TreeScope]::Descendants,$c)}
function Wait-One($Root,[string]$Name,$Type=$null,[int]$Seconds=12){for($i=0;$i-lt $Seconds*5;$i++){$e=Find-One $Root $Name $Type;if($e-and !$e.Current.IsOffscreen){return $e};Start-Sleep -Milliseconds 200};throw "未找到控件：$Name"}
function Invoke-One($Element){$Element.GetCurrentPattern([System.Windows.Automation.InvokePattern]::Pattern).Invoke();Start-Sleep -Milliseconds 500}
function Select-One($Element){$Element.GetCurrentPattern([System.Windows.Automation.SelectionItemPattern]::Pattern).Select();Start-Sleep -Milliseconds 400}
function Find-CardButton($TextElement,[string]$ButtonName){$walker=[System.Windows.Automation.TreeWalker]::ControlViewWalker;$node=$TextElement;for($i=0;$i-lt 8;$i++){$node=$walker.GetParent($node);if(!$node){break};$button=Find-One $node $ButtonName ([System.Windows.Automation.ControlType]::Button);if($button-and!$button.Current.IsOffscreen){return $button}};throw "未找到卡片按钮：$ButtonName"}
function Stop-App($Process){if($Process-and!$Process.HasExited){$Process.Kill();$Process.WaitForExit()}}
$real=Join-Path $env:LOCALAPPDATA 'HMinus\DesktopSpike';$backup="$real.codex-phase5b-$(Get-Date -Format yyyyMMddHHmmssfff)";$had=Test-Path -LiteralPath $real;$app=$null;$clip=[System.Windows.Forms.Clipboard]::GetDataObject();$bitmap=$null
