 Write-Host 'STEP 2 捕获图片并置顶';$bitmap=New-Object System.Drawing.Bitmap 84,62;$graphics=[System.Drawing.Graphics]::FromImage($bitmap);$graphics.Clear([System.Drawing.Color]::FromArgb(255,174,204,180));$graphics.FillEllipse([System.Drawing.Brushes]::White,20,10,42,42);$graphics.Dispose();[System.Windows.Forms.Clipboard]::SetImage($bitmap);$summary=Wait-One $root '图片 84 × 62' ([System.Windows.Automation.ControlType]::Text) 15
 $imageDir=Join-Path $real 'data\clipboard-images';for($i=0;$i-lt 30-and (!(Test-Path $imageDir)-or (Get-ChildItem $imageDir -Filter '*.png' -ErrorAction SilentlyContinue).Count-lt 2);$i++){Start-Sleep -Milliseconds 200};if((Get-ChildItem $imageDir -Filter '*.png').Count-lt 2){throw '未生成原图和缩略图文件'};Invoke-One (Find-CardButton $summary '置顶');$summary=Wait-One $root '图片 84 × 62' ([System.Windows.Automation.ControlType]::Text);$null=Find-CardButton $summary '取消置顶'
 Write-Host 'STEP 3 重启后保留置顶并可取消';Stop-App $app;$app=Start-Process $ExePath -PassThru;$root=Wait-Window $app.Id;Select-One (Wait-One $root '剪贴板' ([System.Windows.Automation.ControlType]::TabItem));$summary=Wait-One $root '图片 84 × 62' ([System.Windows.Automation.ControlType]::Text) 12;Invoke-One (Find-CardButton $summary '取消置顶');$summary=Wait-One $root '图片 84 × 62' ([System.Windows.Automation.ControlType]::Text);$null=Find-CardButton $summary '置顶'
 Write-Host 'STEP 4 删除图片记录、原图和缩略图';Invoke-One (Find-CardButton $summary '删除');for($i=0;$i-lt 30-and (Get-ChildItem $imageDir -File -ErrorAction SilentlyContinue).Count-gt0;$i++){Start-Sleep -Milliseconds 200};if((Get-ChildItem $imageDir -File -ErrorAction SilentlyContinue).Count-gt0){throw '删除后图片目录仍有文件'};if(Find-One $root '图片 84 × 62' ([System.Windows.Automation.ControlType]::Text)){throw '删除后图片卡片仍存在'}
